const body = $input.first().json.body || {};
const message = String(body.message || '').trim();
if (message === 'ping' || body.ping) { return [{ json: { valid: 0, error: 'pong' } }]; }
const token = String(body.token || '').trim().toLowerCase();
if (!token || !/^[a-fA-F0-9]{64}$/.test(token)) { return [{ json: { valid: 0, error: 'auth_required', auth_required: true } }]; }
const action = String(body.action || 'analyze').trim();
const violation = String(body.violation || '').trim().slice(0, 500);
if (action === 'analyze' && !violation) { return [{ json: { valid: 0, error: 'Укажите нарушение' } }]; }
return [{ json: {
  valid: 1, token, action, violation,
  description: String(body.description || '').slice(0, 5000),
  control_object: String(body.control_object || '').slice(0, 300),
  criticality: String(body.criticality || 'medium'),
  risk_level: String(body.risk_level || 'medium'),
  check_results: String(body.check_results || '').slice(0, 5000),
  result: body.result || null,
  incident_id: String(body.incident_id || '')
} }];

const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
if (data && data.error) { return [{ json: { token_valid: false, response: 'error', error: 'database_unavailable' } }]; }
if (!data || !data.user_id) { return [{ json: { token_valid: false, response: 'unauthorized', error: 'unauthorized', auth_required: true } }]; }
return [{ json: Object.assign({}, src, { token_valid: true, user_id: data.user_id }) }];

const rows = $input.all().map(i => i.json).filter(r => r && r.id);
const ctx = $('Token result').first().json;
function toks(s){ return (String(s||'').toLowerCase().match(/[а-яёa-z0-9]{4,}/g) || []); }
const qt = new Set(toks(ctx.violation + ' ' + ctx.description + ' ' + (ctx.check_results || '')));
let best = null, bestScore = 0, bestSim = 0;
for (const r of rows) {
  const rt = toks(r.title + ' ' + r.category + ' ' + (r.description || ''));
  let hit = 0; for (const t of rt) if (qt.has(t)) hit++;
  const tokenNorm = qt.size ? hit / Math.sqrt(qt.size) : 0;
  const sim = (r.sim != null && !isNaN(r.sim)) ? Number(r.sim) : 0;
  const semNorm = sim > 0.75 ? (sim - 0.75) / 0.25 : 0;   // 0.75..1.0 → 0..1
  const combined = Math.max(tokenNorm, semNorm * 1.05);
  if (combined > bestScore) { bestScore = combined; best = r; bestSim = sim; }
}
const semanticHit = !!(best && bestSim >= 0.80);
const matched = !!(best && (semanticHit || bestScore >= 1.0));
return [{ json: Object.assign({}, ctx, {
  matched: matched,
  violation_id: matched ? best.id : null,
  matched_category: matched ? best.category : null,
  matched_processes: matched ? best.processes : null,
  matched_criticality: matched ? best.criticality : null,
  match_score: Math.round(bestScore * 100) / 100,
  match_sim: Math.round(bestSim * 100) / 100,
  match_method: matched ? (semanticHit ? 'semantic' : 'keyword') : 'none'
}) }];

const ctx = $('Сопоставить').first().json;
const row = $('Загрузить связи').first().json || {};
let enrich = null; try { enrich = $('LLM-обогащение').first().json._enrich; } catch (e) {}
let ragRows = []; try { ragRows = $('RAG: нормы').all().map(i => i.json).filter(r => r && r.chunk_text && (r.sim == null || r.sim >= 0.5)); } catch (e) {}
const CRIT = ['low','medium','high','critical'];
function lower(l){ const i = CRIT.indexOf(l); return i > 0 ? CRIT[i-1] : 'low'; }
const measures = { organizational: [], technical: [], administrative: [], controlling: [] };
const just = {};
if (enrich && Array.isArray(enrich.justifications)) for (const j of enrich.justifications) if (j && j.name) just[String(j.name).trim().toLowerCase()] = String(j.text || '');
const rawM = Array.isArray(row.measures) ? row.measures : [];
for (const m of rawM) {
  const t = measures[m.type] ? m.type : 'organizational';
  const lj = just[String(m.name).trim().toLowerCase()];
  measures[t].push({ name: m.name, description: m.description || '', effect: m.effect || '',
    justification: lj || ('Мера относится к категории «' + (row.category || 'нарушение') + '» и снижает связанный риск; рекомендована на основе базы знаний.'), source: 'kb' });
}
let total = rawM.length;
if (enrich && Array.isArray(enrich.suggested)) {
  for (const s of enrich.suggested.slice(0, 3)) {
    if (!s || !s.name) continue;
    const t = measures[s.type] ? s.type : 'organizational';
    if (measures[t].some(x => x.name === s.name)) continue;
    measures[t].push({ name: s.name, description: s.description || '', effect: s.effect || '', justification: 'Предложено ИИ на основе базы знаний и нормативного контекста.', source: 'ai' });
    total++;
  }
}
const BASE = [
  { type:'administrative', name:'Назначить ответственного за устранение нарушения', description:'Закрепить приказом ответственного и срок устранения.', effect:'Персональная ответственность и контроль.' },
  { type:'controlling', name:'Включить нарушение в план контрольных проверок', description:'Добавить пункт в регламент периодических проверок.', effect:'Своевременный контроль устранения.' },
  { type:'organizational', name:'Разработать/обновить регламент по выявленной области', description:'Зафиксировать порядок действий и требования.', effect:'Снижение вероятности повторения.' }
];
let bi = 0;
while (total < 3 && bi < BASE.length) {
  const b = BASE[bi++];
  if (!measures[b.type].some(x => x.name === b.name)) { measures[b.type].push({ name:b.name, description:b.description, effect:b.effect, justification:'Базовая мера устранения и контроля нарушения.', source:'base' }); total++; }
}
const requirements = [];
if (Array.isArray(row.requirements)) for (const r of row.requirements) if (r) requirements.push({ text: r.text, source: r.source });
for (const r of ragRows.slice(0, 3)) requirements.push({ text: String(r.chunk_text).slice(0, 400), source: (((r.doc_name || '') + (r.section ? (', ' + r.section) : '')).trim()) || 'нормативный документ' });
const criticality = ctx.matched_criticality || ctx.criticality || 'medium';
const risk_level = ctx.risk_level || criticality || 'medium';
const residual = lower(risk_level);
const processes = String(row.processes || ctx.matched_processes || '').split(';').map(s => s.trim()).filter(Boolean);
const DL = { critical: ['7 дней','14 дней','30 дней'], high: ['14 дней','30 дней'], medium: ['30 дней'], low: ['45 дней'] };
const deadlines = [];
['technical','organizational','administrative','controlling'].forEach(function(t){ measures[t].forEach(function(m, i){ var d = DL[risk_level] || DL.medium; deadlines.push({ measure: m.name, term: d[Math.min(i, d.length-1)] }); }); });
const summary = (enrich && enrich.summary) ? String(enrich.summary).slice(0, 500) : '';
const result = {
  violation: ctx.violation, category: row.category || ctx.matched_category || 'Не определена',
  criticality: criticality, processes: processes, risk_level: risk_level, residual_risk: residual,
  requirements: requirements, measures: measures, deadlines: deadlines, matched: !!ctx.matched,
  match_method: ctx.match_method || 'none', summary: summary, ai_used: !!enrich,
  note: ctx.matched ? '' : 'Типовое нарушение не найдено в базе знаний — сформированы базовые меры. Рекомендуется уточнить через эксперта или пополнить базу знаний.'
};
return [{ json: { result: result, _save: {
  user_id: ctx.user_id, violation: ctx.violation, description: ctx.description, control_object: ctx.control_object,
  criticality: criticality, risk_level: risk_level, category: result.category, residual_risk: residual, check_results: ctx.check_results || '',
  measures_json: JSON.stringify(measures), report: JSON.stringify(result)
} } }];

// Векторизуем входящее нарушение (офлайн-безопасно: при сбое эмбеддера qvec=null,
// и весь поток откатывается на текстовое сопоставление). АДРЕС эмбеддера здесь:
const EMBED_URL = 'http://130.100.94.119:8001/embed';
const ctx = $('Token result').first().json;
const text = [ctx.violation, ctx.description, ctx.control_object, ctx.check_results].filter(Boolean).join('. ').slice(0, 2000);
let qvec = null;
try {
  const resp = await this.helpers.httpRequest({ method: 'POST', url: EMBED_URL, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ input: text, type: 'query' }), timeout: 8000, json: false });
  const j = (typeof resp === 'string') ? JSON.parse(resp) : resp;
  if (j && Array.isArray(j.embedding) && j.embedding.length) qvec = j.embedding;
} catch (e) { qvec = null; }
return [{ json: Object.assign({}, ctx, { _qvec_str: qvec ? ('[' + qvec.join(',') + ']') : null }) }];

// LLM обогащает обоснования и предлагает доп. меры СТРОГО на основе данных из БЗ
// и RAG-норм (не выдумывает источники). Офлайн-безопасно: сбой → enrich=null,
// детерминированный результат остаётся. АДРЕС LLM здесь:
const LLM_URL = 'http://130.100.95.104:8810/v1/chat/completions';
const ctx = $('Сопоставить').first().json;
const links = $('Загрузить связи').first().json || {};
let ragRows = [];
try { ragRows = $('RAG: нормы').all().map(i => i.json).filter(r => r && r.chunk_text && (r.sim == null || r.sim >= 0.5)); } catch (e) {}
const kbMeasures = Array.isArray(links.measures) ? links.measures : [];
let enrich = null;
try {
  const sys = 'Ты эксперт по информационной безопасности. На основе ПРЕДОСТАВЛЕННЫХ данных из базы знаний и нормативных выдержек сформируй обоснования к мерам и при нехватке предложи дополнительные. СТРОГО: опирайся только на данные ниже, НЕ выдумывай источники нормативных требований. Ответ — ТОЛЬКО валидный JSON, без markdown.';
  const payload = {
    violation: ctx.violation, description: ctx.description || '', category: ctx.matched_category || '',
    kb_measures: kbMeasures.map(m => ({ type: m.type, name: m.name, description: m.description })),
    norms: ragRows.map(r => ({ source: ((r.doc_name || '') + ' ' + (r.section || '')).trim(), text: String(r.chunk_text).slice(0, 500) }))
  };
  const user = 'Данные:\n' + JSON.stringify(payload) + '\n\nВерни JSON вида: {"summary":"1-2 предложения о сути и приоритете устранения","justifications":[{"name":"<точное имя меры из kb_measures>","text":"обоснование почему мера нужна"}],"suggested":[{"type":"organizational|technical|administrative|controlling","name":"короткое имя","description":"что сделать","effect":"что даст"}]}. Если данных мало — suggested может быть пустым.';
  const resp = await this.helpers.httpRequest({ method: 'POST', url: LLM_URL, headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer no-auth' }, body: JSON.stringify({ model: '.', temperature: 0.2, messages: [{ role: 'system', content: sys }, { role: 'user', content: user }] }), timeout: 20000, json: false });
  const j = (typeof resp === 'string') ? JSON.parse(resp) : resp;
  const content = j && j.choices && j.choices[0] && j.choices[0].message && j.choices[0].message.content;
  if (content) { const mm = String(content).match(/\{[\s\S]*\}/); if (mm) enrich = JSON.parse(mm[0]); }
} catch (e) { enrich = null; }
return [{ json: { _enrich: enrich } }];
